{
  "task_name": "情感分析优化",
  "task_description": "判断电商评论的情感倾向是积极(positive)还是消极(negative)",
  "examples": [
    {
      "input": "这个产品质量真的很棒，超出预期！",
      "output": "positive"
    },
    {
      "input": "质量太差了，完全不值这个价格",
      "output": "negative"
    },
    {
      "input": "物流很快，包装也很好，非常满意",
      "output": "positive"
    },
    {
      "input": "客服态度恶劣，再也不来了",
      "output": "negative"
    },
    {
      "input": "性价比很高，值得推荐给朋友",
      "output": "positive"
    }
  ],
  "validation_data": [
    {
      "input": "这家店的东西都很不错",
      "output": "positive"
    },
    {
      "input": "等了一个星期还没发货",
      "output": "negative"
    },
    {
      "input": "宝贝收到了，质量很好",
      "output": "positive"
    },
    {
      "input": "图片和实物差距太大",
      "output": "negative"
    },
    {
      "input": "店家服务态度很好",
      "output": "positive"
    }
  ],
  "initial_prompts": [
    "请判断以下电商评论的情感是positive还是negative。只需要回答一个词。"
  ],
  "max_iterations": 10,
  "num_candidates": 5,
  "top_k": 3,
  "early_stop_threshold": 0.95
}

{
  "task_name": "新闻分类",
  "task_description": "将新闻标题分类为：科技、体育、娱乐、财经",
  "examples": [
    {
      "input": "苹果公司发布新款iPhone 16，搭载最新AI芯片",
      "output": "科技"
    },
    {
      "input": "NBA总决赛今晚开打，湖人对阵勇士",
      "output": "体育"
    },
    {
      "input": "新电影票房破10亿，导演发表获奖感言",
      "output": "娱乐"
    },
    {
      "input": "A股今日大涨3%，创业板指数创新高",
      "output": "财经"
    },
    {
      "input": "特斯拉推出全新电动卡车，续航超1000公里",
      "output": "科技"
    }
  ],
  "validation_data": [
    {
      "input": "人工智能技术取得重大突破",
      "output": "科技"
    },
    {
      "input": "世界杯小组赛今日全部结束",
      "output": "体育"
    },
    {
      "input": "知名演员宣布结婚喜讯",
      "output": "娱乐"
    },
    {
      "input": "央行宣布降息0.25个百分点",
      "output": "财经"
    }
  ],
  "initial_prompts": [
    "请将以下新闻标题分类为：科技、体育、娱乐、财经。只需要回答分类结果。",
    "你是一个新闻分类专家，请判断以下标题属于哪个类别：科技、体育、娱乐、财经"
  ],
  "max_iterations": 8
}

{
  "task_name": "客服问答",
  "task_description": "回答客户关于产品的常见问题",
  "examples": [
    {
      "input": "你们的退货政策是什么？",
      "output": "我们提供7天无理由退货服务，商品需保持完好未使用状态。"
    },
    {
      "input": "多久能发货？",
      "output": "正常情况下，我们会在24小时内发货，偏远地区可能需要2-3天。"
    },
    {
      "input": "支持哪些支付方式？",
      "output": "我们支持微信支付、支付宝、银行卡等多种支付方式。"
    }
  ],
  "validation_data": [
    {
      "input": "可以开发票吗？",
      "output": "可以的，下单时请备注需要开具发票，我们会随货寄出。"
    },
    {
      "input": "运费怎么算？",
      "output": "订单满99元包邮，不满99元需支付10元运费。"
    }
  ],
  "initial_prompts": [
    "你是一个专业的客服助手，请简洁准确地回答客户问题。"
  ],
  "max_iterations": 5
}
